var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레. 지나. 왜. 여. 기 있. 어.</color>","JPN":"<color=#ff3636>レ、ジーナ。ドウシ、テコ、コニイ、ル。</color>","ENG":"<color=#ff3636>Re. Gina. Why. Are you. Here?</color>","TWN":"<color=#ff3636>蕾·佳娜·為什麼·在·這·裡。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희들을 얼릴 수 있다, 라……?","JPN":"我々を凍らせる、と……？","ENG":"I-it's freezing us...?","TWN":"可以凍結我們，嗎……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후훗, 평범한 냉기는 아니네요. 재미있는 메뉴예요.","JPN":"ふふっ、普通の冷気ではありませんね。面白いメニューです。","ENG":"Hah hah. That seems like no ordinary frost. What an interesting menu we have.","TWN":"呵呵，不是普通的寒氣呢。這道菜很有趣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"세라펠과 합중국, 양측에 대부분의 힘을 분할했다고 해도… 이 정도 분전은 기대 이상이에요.","JPN":"セラフェルと合衆国、両側にほとんどの力を分割しているとはいえ……これほどの奮戦は期待以上です。","ENG":"Despite dividing the majority of our forces between Serapel and the States... You have exceeded our expectations.","TWN":"就算我們分出了大部分力量干擾塞拉費爾和合眾國……你能有這種表現，也超出我們的期待了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해서 당신에게 레지나 님을 넘겨드릴 수는 없답니다.","JPN":"でも、だからといってあなたにレジーナ様をお渡しすることはできません。","ENG":"Nevertheless, we will not be handing Miss Regina over to you.","TWN":"不過即便如此，我們也不能把蕾佳娜交給你。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"윽……. 부딪치는 여파만으로도 몸이 휘청거릴 정도네.","JPN":"うっ……ぶつかる余波だけでも体がふらつくわ。","ENG":"Ngh... The impact alone is enough to knock me down.","TWN":"呃……光是碰撞的餘波，就讓人站不穩了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"처음 보는 괴물인데 뭐 하는 녀석이람? 마왕에게 힘으로 덤빈다고?","JPN":"初めて見る怪物だけど、何者かしら。魔王に力勝負を挑むなんて。","ENG":"I've never seen this monster before. What exactly is it? Is it using brute force to defeat a Demon Lord?","TWN":"我第一次看到這種怪物，它是什麼東西？竟敢憑蠻力撲向魔王？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어쩌실래요, 지휘자님? 저희도 가세할까요?","JPN":"どうされますか？　マエストロ。私たちも加勢しましょうか？","ENG":"What shall we do, Chief Conductor? Should we help them?","TWN":"怎麼辦，指揮家？我們也要加入嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"속단하지 마세요, 카르멘. 저희가 맺은 계약은 어디까지나 의식을 돕는 것뿐입니다.","JPN":"速断は禁物です、カルメン。私たちの契約はあくまでも儀式を手伝うことだけです。","ENG":"Do not jump to conclusions, Carmen. We only agreed to assist with the ritual.","TWN":"別輕易下結論，卡門。我們的約定只是幫助完成儀式。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"상황을 충분히 지켜본 뒤 가세해도 늦지 않아요.","JPN":"十分状況を見守ってから加勢しても遅くありません。","ENG":"It will not be too late to help after observing the situation.","TWN":"充分觀察情況後再加入也不遲。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"만에 하나의 가능성이지만, 설령 가아그셰블라께서 고전을 면치 못하셔도……","JPN":"万が一の可能性ですが、たとえガアグシェブラが苦戦を免れなくても……","ENG":"But in the one-in-a-million chance that Gha'agsheblah falters...","TWN":"雖然可能性很小，但萬一加瓦格夫拉陷入苦戰……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저희는 저희대로 합리적인 결정을 내리면 그만이죠. 늘 그랬듯이.","JPN":"私たちは私たちなりの合理的な判断を下せばいいのです。いつもどおりに。","ENG":"We will simply make our decision based on reason, as we have always done.","TWN":"到時候我們再做出合理的決定就行了，就像一直以來那樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"역시 그렇죠? 지휘자님다운 판단이네요.","JPN":"やはりそうですよね？　マエストロらしい判断です。","ENG":"You're right. Good call, Chief Conductor.","TWN":"果然是這種判斷吧？很符合指揮家的風格。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 정신 차리세요!","JPN":"副学会長様、しっかりしてください！","ENG":"Ms. Vice President! Please wake up!","TWN":"副學會長，你醒醒！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저 괴물이 부학회장님을 찾고 있어요. 어서 여기서 도망치셔야 해요.","JPN":"あの怪物が副学会長様を探しています。早くここから逃げないといけません。","ENG":"That monster's looking for you. You must get out of here.","TWN":"那個怪物在找副學會長，你必須快點離開這裡。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};